import{_ as a,o as e,c as i,e as h}from"./app-4cb4de65.js";const r={},d=h('<h1 id="华为目标管理法" tabindex="-1"><a class="header-anchor" href="#华为目标管理法" aria-hidden="true">#</a> 华为目标管理法</h1><h2 id="明确目标" tabindex="-1"><a class="header-anchor" href="#明确目标" aria-hidden="true">#</a> 明确目标</h2><h3 id="组织的意志和行为要体现成果导向" tabindex="-1"><a class="header-anchor" href="#组织的意志和行为要体现成果导向" aria-hidden="true">#</a> 组织的意志和行为要体现成果导向</h3><p>组织成果标准参考</p><ul><li>是否达成组织目标</li><li>既比输出，也比消耗、比待价，看综合贡献</li><li>既比当期，也比前后期，识别当期贡献、组织沉淀、前人贡献</li><li>对组织周边的贡献</li></ul><h3 id="组织整体目标要回归理性-回到主航道" tabindex="-1"><a class="header-anchor" href="#组织整体目标要回归理性-回到主航道" aria-hidden="true">#</a> 组织整体目标要回归理性，回到主航道</h3><p>采取“调整业务体系，剥离非核心业务，建立核心竞争能力”的竞争战略。</p><h3 id="围绕组织目标设定部门或项目目标" tabindex="-1"><a class="header-anchor" href="#围绕组织目标设定部门或项目目标" aria-hidden="true">#</a> 围绕组织目标设定部门或项目目标</h3><p>目标细分得越具体，操作的难度就越小，实现的可能性也就越大。 目标细分要求</p><ul><li>分目标要与组织整体目标始终保持方向一致，目标内容融贯</li><li>各分目标之间在内容与时间上相互协调，保持平衡，并同步发展</li><li>分目标表达要明确和简明扼要，并规定具体的目标值以及完成时限</li></ul><h3 id="利用-smart-将目标明确化" tabindex="-1"><a class="header-anchor" href="#利用-smart-将目标明确化" aria-hidden="true">#</a> 利用”SMART“将目标明确化</h3><p>Specific（具体）、Measurable（可度量）、Achievable/Attainable（可实现）、Relevant（相关）、Time-bound（时限性）。</p><ul><li>目标是什么 <ul><li>保证任务在规定时间高质量完成</li><li>合理安排进度，并控制得当</li><li>明确具体工作对象</li><li>明确操作技术和方案</li><li>明确与目标关联的其他问题</li></ul></li><li>执行目标的合理时间 <ul><li>确定目标执行的具体起始、结束日期</li><li>确定各阶段规定的时间内需要完成的工作任务</li><li>确定突发事件或意外发生时可以宽限的日期和应变措施</li></ul></li><li>执行目标适宜的地点 <ul><li>选择适合工作开展的任务点</li><li>选择适合的物资采购点，保障物资尽快安全运达</li><li>选择适合存储和管理设备、物资的地点</li></ul></li><li>操作目的 <ul><li>明确为什么要进行此项任务</li><li>明确这项任务将会创造的收益，以及是否符合市场需求</li><li>任务完成后，创造的产品或服务能够快速为客户所接受</li></ul></li><li>怎样操作 <ul><li>找出能让操作速度更快、更省时省力，并且能够避免失误造成的时间浪费的方法</li></ul></li></ul><p>企业在目标管理中，尤其要注重时量、数量和质量的量化指标，即达成目标的时间量，完成工作的数量，完成工作的程度和标准。</p><h3 id="构建导向关键措施的目标分解图" tabindex="-1"><a class="header-anchor" href="#构建导向关键措施的目标分解图" aria-hidden="true">#</a> 构建导向关键措施的目标分解图</h3><h3 id="各级目标自下而上融合总目标" tabindex="-1"><a class="header-anchor" href="#各级目标自下而上融合总目标" aria-hidden="true">#</a> 各级目标自下而上融合总目标</h3><p>个人目标与企业目标合二为一</p><ul><li>员工能力培训 提升员工能力，让员工感受到企业的支持和重视，同时让员工认同企业的目标和文化</li><li>绩效管理 以员工能否完成工作任务作为奖惩，将员工利益和企业捆绑在一起</li><li>同向发展 让企业的发展为个人的发展提供更广阔的空间和机遇</li></ul><h2 id="目标沟通与决策" tabindex="-1"><a class="header-anchor" href="#目标沟通与决策" aria-hidden="true">#</a> 目标沟通与决策</h2><h3 id="以团队目标强化群体奋斗观念" tabindex="-1"><a class="header-anchor" href="#以团队目标强化群体奋斗观念" aria-hidden="true">#</a> 以团队目标强化群体奋斗观念</h3><p>一个人的英雄主义对团队的帮助是有限的，只有集体英雄主义才是强大的。</p><h3 id="团队内部对齐信息-上下同欲" tabindex="-1"><a class="header-anchor" href="#团队内部对齐信息-上下同欲" aria-hidden="true">#</a> 团队内部对齐信息，上下同欲</h3><p>当目标确立后，团队所有的信息应该围绕目标而收集。企业要运用一切资源帮助团队建立信息共享的通道，增强员工的集体意识，让团队成员懂得分享，并善于利用团队信息来完成自己的工作。 “3R”​，即 Recognize（认同）, Respect（尊重）, Reaction（行动）​。 没有带头大哥。</p><h3 id="通过沟通达成一致目标" tabindex="-1"><a class="header-anchor" href="#通过沟通达成一致目标" aria-hidden="true">#</a> 通过沟通达成一致目标</h3><table><thead><tr><th>沟通对象</th><th>沟通方法</th></tr></thead><tbody><tr><td>同级之间沟通</td><td>明确自己在团队中的位置，同级之间应该是合作伙伴的关系；帮助他人，也要积极主动寻求他人的帮助</td></tr><tr><td>与上级沟通</td><td>了解上级的管理风格、思维方式、沟通方式；主动配合上级的管理</td></tr><tr><td>与下级沟通</td><td>预先通知对方；打破沟通的紧张气氛；了解对方心态，先听取对方意见，为对方着想；以事实为依据，结合日常观察，针对目标进行沟通</td></tr><tr><td>与客户沟通</td><td>客户是上帝，态度要诚恳；根据实际情况选择采用口头还是书面沟通；在自己的职责范围内对客户做该做的事，说该说的化</td></tr></tbody></table><h3 id="利用决策会议完成目标动员" tabindex="-1"><a class="header-anchor" href="#利用决策会议完成目标动员" aria-hidden="true">#</a> 利用决策会议完成目标动员</h3><p>目标宣讲</p><h3 id="用-pbc-实现自我激励和监督" tabindex="-1"><a class="header-anchor" href="#用-pbc-实现自我激励和监督" aria-hidden="true">#</a> 用“PBC”实现自我激励和监督</h3><p>员工达成目标，不能依赖企业的监督机制，更重要的是要自觉达成目标。 PBC（Personal Business Commitment）即个人业务承诺。</p><ul><li>业务目标 <ul><li>关键指标 KPI</li><li>关键任务衡量指标</li><li>业务目标对组织建设、员工管理的要求</li></ul></li><li>员工管理目标 <ul><li>年度计划中人员管理</li><li>领导力素质模型</li><li>管理者岗位要求</li></ul></li><li>个人发展目标 <ul><li>回顾业务目标，确定目标完成还应提升哪些方面的能力</li><li>设定几个目标来提升自己的能力</li></ul></li></ul><p>PBC 考察指标</p><ul><li>结果目标承诺：员工承诺在考核期内要达成什么样的绩效结果目标，以支持部门目标的实现</li><li>执行措施承诺：员工与考核者对完成绩效目标的方法和执行措施达成共识，并将执行措施作为考核的重要部分，以确保结果目标能实现</li><li>团队合作承诺：员工与团队成员在交流、参与、理解和相互支持等方面做出承诺，为保证团队绩效高效达成</li></ul><p>PBC 表现体现在承诺必胜（win）​、承诺执行（execute）​、承诺团队精神（team）三方面。承诺必胜（win）​，是指要想完成任务，就必须抱着必胜的决心，而这又离不开团队高效的合作；承诺执行（execute）​，是指员工制定承诺后要时刻想着去执行，完成项目更为重要的是执行，而且贯穿于项目落实的全过程；承诺团队精神（team）​，是指员工发挥团队力量、共同合作才有可能取得成功。</p><h3 id="制造同侪压力-促进共同进步" tabindex="-1"><a class="header-anchor" href="#制造同侪压力-促进共同进步" aria-hidden="true">#</a> 制造同侪压力，促进共同进步</h3><p>内部比武。</p><h2 id="目标控制与分解" tabindex="-1"><a class="header-anchor" href="#目标控制与分解" aria-hidden="true">#</a> 目标控制与分解</h2><h3 id="目标要转化为具体的行动计划" tabindex="-1"><a class="header-anchor" href="#目标要转化为具体的行动计划" aria-hidden="true">#</a> 目标要转化为具体的行动计划</h3><h3 id="帮助下属设置合理的目标" tabindex="-1"><a class="header-anchor" href="#帮助下属设置合理的目标" aria-hidden="true">#</a> 帮助下属设置合理的目标</h3><p>下级自身产生的阻力</p><ul><li>与上级讨价还价，压低工作目标</li><li>对工作目标没有概念</li><li>习惯于等待上级下达命令或指示</li><li>不懂得如何将个人目标与部门目标甚至企业目标相统一</li></ul><h3 id="在成果评价标准上要达成共识" tabindex="-1"><a class="header-anchor" href="#在成果评价标准上要达成共识" aria-hidden="true">#</a> 在成果评价标准上要达成共识</h3><h3 id="贯彻人人对事负责的目标责任制" tabindex="-1"><a class="header-anchor" href="#贯彻人人对事负责的目标责任制" aria-hidden="true">#</a> 贯彻人人对事负责的目标责任制</h3><h3 id="用目标管理卡规范目标" tabindex="-1"><a class="header-anchor" href="#用目标管理卡规范目标" aria-hidden="true">#</a> 用目标管理卡规范目标</h3><p><img src="https://res.weread.qq.com/wrepub/epub_23914338_22" alt=""><img src="https://res.weread.qq.com/wrepub/epub_23914338_23" alt=""><img src="https://res.weread.qq.com/wrepub/epub_23914338_24" alt=""></p><h3 id="借助任务清单和看板完善目标管理" tabindex="-1"><a class="header-anchor" href="#借助任务清单和看板完善目标管理" aria-hidden="true">#</a> 借助任务清单和看板完善目标管理</h3><p><img src="https://res.weread.qq.com/wrepub/epub_23914338_25" alt=""><img src="https://res.weread.qq.com/wrepub/epub_23914338_26" alt=""><img src="https://res.weread.qq.com/wrepub/epub_23914338_27" alt=""></p><h2 id="时间规划与管理" tabindex="-1"><a class="header-anchor" href="#时间规划与管理" aria-hidden="true">#</a> 时间规划与管理</h2><p>如果你发觉自己没有足够的时间去做真正重要的事，那么你必须学会减少你的责任，这样你才能有足够的精力和时间。</p><h3 id="拟定实现目标的最佳作战路径" tabindex="-1"><a class="header-anchor" href="#拟定实现目标的最佳作战路径" aria-hidden="true">#</a> 拟定实现目标的最佳作战路径</h3><p>将任务按照重要性和紧迫性归入时间管理目标中。</p><h3 id="输出任务计划和风险规避方案" tabindex="-1"><a class="header-anchor" href="#输出任务计划和风险规避方案" aria-hidden="true">#</a> 输出任务计划和风险规避方案</h3><h3 id="设定任务阶段时间点与最后期限值" tabindex="-1"><a class="header-anchor" href="#设定任务阶段时间点与最后期限值" aria-hidden="true">#</a> 设定任务阶段时间点与最后期限值</h3><p><img src="https://res.weread.qq.com/wrepub/epub_23914338_28" alt=""></p><h3 id="清除干扰-保障工作节奏" tabindex="-1"><a class="header-anchor" href="#清除干扰-保障工作节奏" aria-hidden="true">#</a> 清除干扰，保障工作节奏</h3><h3 id="坚持跑步上岗-立即执行" tabindex="-1"><a class="header-anchor" href="#坚持跑步上岗-立即执行" aria-hidden="true">#</a> 坚持跑步上岗，立即执行</h3><h3 id="以事事闭环的态度投入到工作中" tabindex="-1"><a class="header-anchor" href="#以事事闭环的态度投入到工作中" aria-hidden="true">#</a> 以事事闭环的态度投入到工作中</h3><h2 id="组织与实施" tabindex="-1"><a class="header-anchor" href="#组织与实施" aria-hidden="true">#</a> 组织与实施</h2><h3 id="主动整合资源-优化管理" tabindex="-1"><a class="header-anchor" href="#主动整合资源-优化管理" aria-hidden="true">#</a> 主动整合资源，优化管理</h3><h3 id="坚持-压强原则-聚焦工作" tabindex="-1"><a class="header-anchor" href="#坚持-压强原则-聚焦工作" aria-hidden="true">#</a> 坚持“压强原则”，聚焦工作</h3><h3 id="充分授权-让员工能干-敢干" tabindex="-1"><a class="header-anchor" href="#充分授权-让员工能干-敢干" aria-hidden="true">#</a> 充分授权，让员工能干，敢干</h3><h3 id="帮助员工融入团队-做好-传、帮、带" tabindex="-1"><a class="header-anchor" href="#帮助员工融入团队-做好-传、帮、带" aria-hidden="true">#</a> 帮助员工融入团队，做好“传、帮、带”</h3><h3 id="遵循已有的流程规范执行" tabindex="-1"><a class="header-anchor" href="#遵循已有的流程规范执行" aria-hidden="true">#</a> 遵循已有的流程规范执行</h3><h3 id="坚持汇报和沟通机制" tabindex="-1"><a class="header-anchor" href="#坚持汇报和沟通机制" aria-hidden="true">#</a> 坚持汇报和沟通机制</h3><p><img src="https://res.weread.qq.com/wrepub/epub_23914338_34" alt=""></p><h2 id="过程检查与反馈" tabindex="-1"><a class="header-anchor" href="#过程检查与反馈" aria-hidden="true">#</a> 过程检查与反馈</h2><h3 id="厘清并明确任务关键控制点" tabindex="-1"><a class="header-anchor" href="#厘清并明确任务关键控制点" aria-hidden="true">#</a> 厘清并明确任务关键控制点</h3><h3 id="全程跟踪目标执行的进度" tabindex="-1"><a class="header-anchor" href="#全程跟踪目标执行的进度" aria-hidden="true">#</a> 全程跟踪目标执行的进度</h3><h3 id="积极自我检查与改善" tabindex="-1"><a class="header-anchor" href="#积极自我检查与改善" aria-hidden="true">#</a> 积极自我检查与改善</h3><h3 id="检查目标实施情况-并予以反馈" tabindex="-1"><a class="header-anchor" href="#检查目标实施情况-并予以反馈" aria-hidden="true">#</a> 检查目标实施情况，并予以反馈</h3><h3 id="就目标完成状况进行阶段性总结和交流" tabindex="-1"><a class="header-anchor" href="#就目标完成状况进行阶段性总结和交流" aria-hidden="true">#</a> 就目标完成状况进行阶段性总结和交流</h3><h3 id="找准位置切入-快速修正目标计划" tabindex="-1"><a class="header-anchor" href="#找准位置切入-快速修正目标计划" aria-hidden="true">#</a> 找准位置切入，快速修正目标计划</h3><h2 id="目标评价管理" tabindex="-1"><a class="header-anchor" href="#目标评价管理" aria-hidden="true">#</a> 目标评价管理</h2><h3 id="公平、公正地评价下属绩效" tabindex="-1"><a class="header-anchor" href="#公平、公正地评价下属绩效" aria-hidden="true">#</a> 公平、公正地评价下属绩效</h3><p>奖励员工方面常犯的十大错误 <img src="https://res.weread.qq.com/wrepub/epub_23914338_43" alt=""></p><h3 id="完不成目标的团队-全员受罚" tabindex="-1"><a class="header-anchor" href="#完不成目标的团队-全员受罚" aria-hidden="true">#</a> 完不成目标的团队，全员受罚</h3><h3 id="不达底线目标-绩效为零" tabindex="-1"><a class="header-anchor" href="#不达底线目标-绩效为零" aria-hidden="true">#</a> 不达底线目标，绩效为零</h3><h3 id="不让奋斗着吃亏-按贡献大小拿待遇" tabindex="-1"><a class="header-anchor" href="#不让奋斗着吃亏-按贡献大小拿待遇" aria-hidden="true">#</a> 不让奋斗着吃亏，按贡献大小拿待遇</h3><p>按贡献来评定项目大小，能为公司赚大钱的就是大项目，为公司赚小钱的就是小项目。</p><h3 id="让拉车的人比坐车的人拿的多" tabindex="-1"><a class="header-anchor" href="#让拉车的人比坐车的人拿的多" aria-hidden="true">#</a> 让拉车的人比坐车的人拿的多</h3><h3 id="在绩效评价的牵引下持续奋斗" tabindex="-1"><a class="header-anchor" href="#在绩效评价的牵引下持续奋斗" aria-hidden="true">#</a> 在绩效评价的牵引下持续奋斗</h3>',80),l=[d];function t(n,s){return e(),i("div",null,l)}const u=a(r,[["render",t],["__file","华为目标管理法.html.vue"]]);export{u as default};
